SELECT id, tenant_code, name, type, enabled, expire_at, is_deleted, created_at, updated_at
FROM tenant
WHERE is_deleted = FALSE

    AND (tenant_code ILIKE CONCAT('%', #{keyword}, '%') OR name ILIKE CONCAT('%', #{keyword}, '%'))


    AND type = #{type}


    AND enabled = #{enabled}

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

